#include <stdio.h>
int maxProfit(int* profits, int n, int k) {
    int maxProfit = 0;
    for (int i = 0; i <= n - k; i++) {
        int sum = 0;
        for (int j = i; j < i + k; j++) {
            sum += profits[j];
        }
        maxProfit = (sum > maxProfit) ? sum : maxProfit;
    }
    return maxProfit;
}
int main() {
    int n, k;
    scanf("%d %d", &n, &k);
    int* profits = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &profits[i]);
    }
    printf("%d\n", maxProfit(profits, n, k));
    free(profits);
    return 0;
}

